1	const PROCESSING_FEE = 5;
2	const COMPONENT_PREMIUM = 25;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	const COMPONENT_BLOCK_SIZE = 3;
5	const CURSED_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	
9	const MAIN_ITEMS: Record<string, { premium: number; insuranceValue: number }> = {
10	  sword: { premium: 100, insuranceValue: 1000 },
11	  amulet: { premium: 60, insuranceValue: 600 },
12	  staff: { premium: 80, insuranceValue: 800 },
13	  potion: { premium: 40, insuranceValue: 400 },
14	};
